{"command": "cd /data/zrwang/auto-opt/utils/llvm-157371 && cat << 'EOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Analysis/InstructionSimplify.cpp 1853 1853
  // Handle redundant comparisons with constants:
  // (X pred C1) | (X pred C2) --> X pred max(C1, C2) for less-than predicates
  // (X pred C1) | (X pred C2) --> X pred min(C1, C2) for greater-than predicates
  // (X pred C1) & (X pred C2) --> X pred min(C1, C2) for less-than predicates
  // (X pred C1) & (X pred C2) --> X pred max(C1, C2) for greater-than predicates
  const APFloat *C0 = nullptr, *C1 = nullptr;
  Value *X = nullptr;
  bool Swapped0 = false, Swapped1 = false;

  // Check if both comparisons have the same variable X and different constants
  // Case 1: X is operand 0 in both (X pred C)
  if (LHS0 == RHS0 && match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
    X = LHS0;
    Swapped0 = Swapped1 = false;
  }
  // Case 2: X is operand 1 in both (C pred X, which is X swapped_pred C)
  else if (LHS1 == RHS1 && match(LHS0, m_APFloat(C0)) && match(RHS0, m_APFloat(C1))) {
    X = LHS1;
    Swapped0 = Swapped1 = true;
  }
  // Case 3: X is LHS operand 0, RHS operand 1
  else if (LHS0 == RHS1 && match(LHS1, m_APFloat(C0)) && match(RHS0, m_APFloat(C1))) {
    X = LHS0;
    Swapped0 = false;
    Swapped1 = true;
  }
  // Case 4: X is LHS operand 1, RHS operand 0
  else if (LHS1 == RHS0 && match(LHS0, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
    X = LHS1;
    Swapped0 = true;
    Swapped1 = false;
  }

  if (X && C0 && C1) {
    // Get the effective predicates (swapped if the constant is on the left)
    FCmpInst::Predicate EffPred0 = Swapped0 ? FCmpInst::getSwappedPredicate(PredL) : PredL;
    FCmpInst::Predicate EffPred1 = Swapped1 ? FCmpInst::getSwappedPredicate(PredR) : PredR;

    // Both predicates must be the same after normalization
    if (EffPred0 == EffPred1) {
      FCmpInst::Predicate Pred = EffPred0;

      // Check if predicate is a less-than or greater-than type
      bool IsLessThan = (Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_OLE ||
                         Pred == FCmpInst::FCMP_ULT || Pred == FCmpInst::FCMP_ULE);
      bool IsGreaterThan = (Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_OGE ||
                            Pred == FCmpInst::FCMP_UGT || Pred == FCmpInst::FCMP_UGE);

      if (IsLessThan || IsGreaterThan) {
        // For AND: take the more restrictive comparison (min for <, max for >)
        // For OR: take the less restrictive comparison (max for <, min for >)
        bool UseSmallerConstant = (IsAnd && IsLessThan) || (!IsAnd && IsGreaterThan);
        bool C0IsSmaller = (*C0 < *C1);
        const APFloat *RetC = (C0IsSmaller == UseSmallerConstant) ? C0 : C1;

        return new FCmpInst(Pred, X, ConstantFP::get(X->getType(), *RetC));
      }
    }
  }

  return nullptr;
EOF
"}

